{"content":"/* ===== Base & layout ===== */
:root {
  --bg-deep: #02030a;
  --bg-panel: rgba(8, 12, 24, 0.78);
  --bg-panel-strong: rgba(8, 12, 24, 0.94);
  --border: rgba(120, 160, 220, 0.18);
  --border-strong: rgba(120, 160, 220, 0.35);
  --fg: #e6ecf5;
  --fg-mute: #95a3b8;
  --fg-dim: #6a768a;
  --accent: #6cc4ff;
  --accent-warm: #ffba6c;
  --danger: #ff5d6c;
  --safe: #6cff9e;
  --shadow: 0 6px 22px rgba(0, 0, 0, 0.55);
  --radius: 8px;
  --radius-sm: 4px;
  --mono: ui-monospace, "SF Mono", "JetBrains Mono", "Fira Code", Menlo, Consolas, monospace;
  --sans: -apple-system, BlinkMacSystemFont, "Segoe UI", "Inter", Roboto, sans-serif;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  width: 100%;
  height: 100%;
  background: var(--bg-deep);
  color: var(--fg);
  font-family: var(--sans);
  overflow: hidden;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

#scene {
  display: block;
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  cursor: grab;
  background:
    radial-gradient(ellipse at 50% 50%, #060912 0%, #02030a 60%, #000 100%);
}

#scene:active {
  cursor: grabbing;
}

.hidden {
  display: none !important;
}

.app {
  position: fixed;
  inset: 0;
}

/* ===== Loading ===== */
.loading {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bg-deep);
  z-index: 999;
}

.loading-card {
  background: var(--bg-panel-strong);
  border: 1px solid var(--border-strong);
  padding: 28px 36px;
  border-radius: var(--radius);
  text-align: center;
  min-width: 320px;
  box-shadow: var(--shadow);
}

.loading-title {
  font-size: 14px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--fg-mute);
  margin-bottom: 18px;
}

.loading-bar {
  width: 100%;
  height: 6px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 3px;
  overflow: hidden;
  margin-bottom: 10px;
}

.loading-bar-fill {
  height: 100%;
  width: 0%;
  background: linear-gradient(90deg, var(--accent), var(--accent-warm));
  transition: width 180ms ease;
}

.loading-status {
  font-family: var(--mono);
  font-size: 11px;
  color: var(--fg-dim);
}

/* ===== Panels ===== */
.panel {
  position: absolute;
  background: var(--bg-panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 12px 14px;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: var(--shadow);
  pointer-events: auto;
  user-select: none;
  font-size: 12px;
  z-index: 10;
}

.panel-top-left {
  top: 14px;
  left: 14px;
  max-width: 240px;
}

.panel-top-right {
  top: 14px;
  right: 14px;
  width: 320px;
  max-height: calc(100vh - 200px);
  overflow: auto;
}

.panel-bottom-left {
  bottom: 14px;
  left: 14px;
  width: 380px;
  max-height: 60vh;
  overflow: auto;
}

.panel-bottom-right {
  bottom: 14px;
  right: 14px;
  width: 460px;
}

.panel-title {
  font-size: 13px;
  font-weight: 600;
  color: var(--fg);
  margin-bottom: 2px;
  letter-spacing: 0.01em;
}

.panel-sub {
  font-size: 11px;
  color: var(--fg-mute);
  margin-bottom: 10px;
}

.panel-meta {
  display: grid;
  gap: 4px;
  font-family: var(--mono);
  font-size: 11px;
  color: var(--fg);
  margin-top: 8px;
}

.meta-label {
  color: var(--fg-dim);
  display: inline-block;
  min-width: 50px;
}

/* ===== Filters ===== */
.filter-row {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  margin-bottom: 8px;
  align-items: center;
}

.toggle {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  cursor: pointer;
  padding: 4px 8px;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: rgba(255, 255, 255, 0.02);
  font-size: 11px;
  color: var(--fg-mute);
  transition: all 120ms ease;
}

.toggle:hover {
  border-color: var(--border-strong);
  color: var(--fg);
}

.toggle input {
  margin: 0;
  accent-color: var(--accent);
}

.toggle input:checked + span {
  color: var(--fg);
}

.select {
  display: inline-flex;
  flex-direction: column;
  gap: 2px;
  font-size: 10px;
  color: var(--fg-dim);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.select select,
.select input {
  background: rgba(0, 0, 0, 0.4);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 4px 6px;
  font-size: 11px;
  font-family: var(--mono);
  outline: none;
}

.select select:focus,
.select input:focus {
  border-color: var(--accent);
}

.select-inline {
  background: rgba(0, 0, 0, 0.4);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 4px 6px;
  font-size: 11px;
  font-family: var(--mono);
  outline: none;
}

.search {
  display: inline-flex;
  flex-direction: column;
  gap: 2px;
  font-size: 10px;
  color: var(--fg-dim);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  flex: 1;
  min-width: 180px;
}

.search input {
  background: rgba(0, 0, 0, 0.4);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 5px 8px;
  font-size: 12px;
  font-family: var(--mono);
  outline: none;
}

.search input:focus {
  border-color: var(--accent);
}

.btn {
  background: rgba(255, 255, 255, 0.05);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 5px 10px;
  font-size: 11px;
  cursor: pointer;
  font-family: var(--mono);
  transition: all 120ms ease;
}

.btn:hover {
  background: rgba(255, 255, 255, 0.1);
  border-color: var(--border-strong);
}

.btn-primary {
  background: var(--accent);
  color: #001220;
  border-color: var(--accent);
  font-weight: 600;
}

.btn-primary:hover {
  background: #8cd4ff;
  border-color: #8cd4ff;
}

/* ===== Time panel ===== */
.time-row {
  display: flex;
  gap: 6px;
  margin-bottom: 8px;
  align-items: center;
}

.time-row-sub {
  justify-content: space-between;
  font-family: var(--mono);
  font-size: 10px;
  color: var(--fg-dim);
}

#time-jump {
  flex: 1;
  background: rgba(0, 0, 0, 0.4);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 5px 8px;
  font-size: 11px;
  font-family: var(--mono);
  outline: none;
}

#time-jump:focus {
  border-color: var(--accent);
}

.scrub {
  width: 100%;
  margin: 6px 0;
  accent-color: var(--accent);
}

.time-legend {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 6px;
  padding-top: 8px;
  border-top: 1px solid var(--border);
  font-family: var(--mono);
  font-size: 10px;
  color: var(--fg-mute);
}

.dot {
  display: inline-block;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  margin-right: 4px;
  vertical-align: middle;
}

.dot-neo {
  background: #8db4ff;
}
.dot-pha {
  background: var(--danger);
}
.dot-sentry {
  background: var(--accent-warm);
}
.dot-comet {
  background: #b6d6ff;
}
.dot-planet {
  background: #ffd66c;
}

/* ===== Detail panel ===== */
.detail-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px 12px;
  margin: 8px 0;
  font-family: var(--mono);
  font-size: 11px;
}

.detail-grid div span:first-child {
  color: var(--fg-dim);
}

.detail-section {
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
}

.detail-section-title {
  font-size: 11px;
  color: var(--fg-mute);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 6px;
}

.table-wrap {
  max-height: 200px;
  overflow: auto;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
}

.table {
  width: 100%;
  border-collapse: collapse;
  font-family: var(--mono);
  font-size: 10.5px;
}

.table th,
.table td {
  padding: 4px 8px;
  text-align: right;
  border-bottom: 1px solid var(--border);
}

.table th {
  background: rgba(255, 255, 255, 0.03);
  color: var(--fg-mute);
  font-weight: 500;
  position: sticky;
  top: 0;
}

.table td:first-child,
.table th:first-child {
  text-align: left;
}

.table tbody tr:hover {
  background: rgba(108, 196, 255, 0.06);
  cursor: pointer;
}

.detail-actions {
  display: flex;
  gap: 6px;
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px solid var(--border);
}

/* ===== Tooltip ===== */
.tooltip {
  position: fixed;
  pointer-events: none;
  background: var(--bg-panel-strong);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius-sm);
  padding: 6px 10px;
  font-family: var(--mono);
  font-size: 11px;
  color: var(--fg);
  z-index: 50;
  white-space: nowrap;
  box-shadow: var(--shadow);
}

.tooltip .tip-name {
  font-weight: 600;
  color: var(--accent);
}

.tooltip .tip-sub {
  color: var(--fg-mute);
  font-size: 10px;
  margin-top: 2px;
}

/* ===== Toast ===== */
.toast {
  position: fixed;
  bottom: 80px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--bg-panel-strong);
  border: 1px solid var(--accent);
  color: var(--fg);
  padding: 8px 14px;
  border-radius: var(--radius-sm);
  font-size: 12px;
  font-family: var(--mono);
  z-index: 100;
  box-shadow: var(--shadow);
  animation: toast-in 200ms ease;
}

@keyframes toast-in {
  from {
    opacity: 0;
    transform: translateX(-50%) translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateX(-50%) translateY(0);
  }
}

/* ===== Scrollbar ===== */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.08);
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.16);
}

/* ===== Responsive ===== */
@media (max-width: 900px) {
  .panel-top-right {
    width: 280px;
  }
  .panel-bottom-right {
    width: calc(100vw - 28px);
  }
  .panel-bottom-left {
    width: calc(100vw - 28px);
  }
}
