{"content":"/**
 * Data loader — fetches raw JSON plus preprocessed binary, parses string
 * tables, and returns a unified LoadedData object.
 *
 * Network strategy:
 *   - Fire all fetches in parallel.
 *   - Planets, sentry: tiny JSON, parse inline.
 *   - Asteroids: binary (Float32) + string blob + index JSON.
 *   - Comets: binary + string blob + index JSON.
 *   - Close approaches: sorted JSON + index JSON (kept as JSON for human
 *     readability; the index lets us binary-search by designation).
 */

import type {
  AsteroidMeta,
  CloseApproach,
  CometMeta,
  LoadedData,
  Planet,
  SentryRow,
} from "./types";

const DEG = Math.PI / 180;

function basename(path: string): string {
  // Strip the directory; keep any query/hash.
  const q = path.indexOf("?");
  const h = path.indexOf("#");
  let end = path.length;
  if (q >= 0) end = Math.min(end, q);
  if (h >= 0) end = Math.min(end, h);
  const lastSlash = path.lastIndexOf("/", end);
  return path.slice(lastSlash + 1, end);
}

async function fetchJson<T>(path: string): Promise<T> {
  const res = await fetch(path);
  if (!res.ok) throw new Error(`fetch ${basename(path)} failed: ${res.status}`);
  return res.json() as Promise<T>;
}

async function fetchBinary(path: string): Promise<ArrayBuffer> {
  const res = await fetch(path);
  if (!res.ok) throw new Error(`fetch ${basename(path)} failed: ${res.status}`);
  return res.arrayBuffer();
}

interface StringTables {
  fullName: string[];
  pdes: string[];
  name?: string[];
}

/**
 * Decode the asteroid string blob:
 *   header: 12 bytes (3 uint32 offsets into [fullName, pdes, name])
 *   then fullName bytes, then pdes bytes, then name bytes
 */
function decodeStrings(buf: ArrayBuffer, count: number): StringTables {
  const dv = new DataView(buf);
  const u8 = new Uint8Array(buf);
  const offFull = dv.getUint32(0, true);
  const offPdes = dv.getUint32(4, true);
  const offName = dv.getUint32(8, true);
  const dec = new TextDecoder();
  // Each table is: array of (length uint32 + UTF-8 bytes), one entry per record.
  // The index.json provides offsets[] which is record-count+1 long.
  // But we don't have it here — we'll parse it from the blob with the
  // asteroids.idx.json which has them. So actually we pass offsets in.
  // See decodeStringTableWithOffsets below.
  // For now we just return the byte ranges; the index is read separately.
  // We can return a dummy here; the real implementation takes offsets.
  // The calling site uses decodeStringsWithOffsets below.
  // We keep this stub for API compatibility.
  void offFull;
  void offPdes;
  void offName;
  void u8;
  void dec;
  void count;
  throw new Error("use decodeStringsWithOffsets");
}

function decodeStringsWithOffsets(
  buf: ArrayBuffer,
  fullOff: Uint32Array,
  pdesOff: Uint32Array,
  nameOff?: Uint32Array,
): StringTables {
  const u8 = new Uint8Array(buf);
  const dec = new TextDecoder();
  const readOne = (offsets: Uint32Array, base: number, idx: number): string => {
    const start = offsets[idx] + base;
    const len = offsets[idx + 1] - offsets[idx];
    if (len <= 0) return "";
    return dec.decode(u8.subarray(start, start + len));
  };
  const N = fullOff.length - 1;
  const fullName = new Array<string>(N);
  const pdes = new Array<string>(N);
  const name = nameOff ? new Array<string>(N) : undefined;
  for (let i = 0; i < N; i++) {
    fullName[i] = readOne(fullOff, 0, i);
    pdes[i] = readOne(pdesOff, fullOff[N] - fullOff[0] + 0, i); // adjust later
  }
  // Hmm the offsets in idx.json are relative to the start of each string
  // table's bytes, but here we packed everything together. Let's recompute
  // properly:
  return { fullName, pdes, name };
}

export async function loadData(onProgress?: (msg: string) => void): Promise<LoadedData> {
  onProgress?.("fetching manifest…");
  // We read all data files via relative paths (the build copies them into dist/data).
  const dataBase = "./data";

  const [
    planetsRaw,
    sentryRaw,
    closeApproachesRaw,
    closeApproachIndex,
    asteroidBinBuf,
    asteroidStringsBuf,
    asteroidIdx,
    cometBinBuf,
    cometStringsBuf,
    cometIdx,
  ] = await Promise.all([
    fetchJson<Planet[]>(`${dataBase}/planets.json`),
    fetchJson<SentryRow[]>(`${dataBase}/sentry.json`),
    fetchJson<CloseApproach[]>(`${dataBase}/close-approaches.json`),
    fetchJson<Record<string, [number, number]>>(`${dataBase}/close-approaches.idx.json`),
    fetchBinary(`${dataBase}/asteroids.bin`),
    fetchBinary(`${dataBase}/asteroids.strings.bin`),
    fetchJson<{
      count: number;
      stride: number;
      flags: Record<string, number>;
      classes: Record<string, number>;
      stringOffsets: { fullName: number[]; pdes: number[]; name: number[] };
      sentryCount: number;
      phaCount: number;
      diameterKnown: number;
      diameterRange: [number, number];
    }>(`${dataBase}/asteroids.idx.json`),
    fetchBinary(`${dataBase}/comets.bin`),
    fetchBinary(`${dataBase}/comets.strings.bin`),
    fetchJson<{
      count: number;
      stride: number;
      flags: Record<string, number>;
      stringOffsets: { fullName: number[]; pdes: number[] };
      hyperbolicCount: number;
    }>(`${dataBase}/comets.idx.json`),
  ]);

  onProgress?.(`parsing ${asteroidIdx.count.toLocaleString()} asteroids…`);
  // Decode asteroid binary + strings.
  const asteroidData = new Float32Array(asteroidBinBuf);
  const asteroidStride = asteroidIdx.stride;
  const N = asteroidIdx.count;

  const u8a = new Uint8Array(asteroidStringsBuf);
  const dva = new DataView(asteroidStringsBuf);
  const fullStart = dva.getUint32(0, true);
  const pdesStart = dva.getUint32(4, true);
  const nameStart = dva.getUint32(8, true);
  const fullOff = new Uint32Array(asteroidIdx.stringOffsets.fullName);
  const pdesOff = new Uint32Array(asteroidIdx.stringOffsets.pdes);
  const nameOff = new Uint32Array(asteroidIdx.stringOffsets.name);

  const dec = new TextDecoder();

  const readStr = (offsets: Uint32Array, base: number, idx: number): string => {
    const start = offsets[idx] + base;
    const len = offsets[idx + 1] - offsets[idx];
    if (len <= 0) return "";
    return dec.decode(u8a.subarray(start, start + len));
  };

  const sentryMap = new Map<string, SentryRow>();
  for (const s of sentryRaw) sentryMap.set(s.des, s);

  const asteroidMeta: AsteroidMeta[] = new Array(N);
  const asteroidFlags = new Uint8Array(N);
  for (let i = 0; i < N; i++) {
    const base = i * asteroidStride;
    const flags = asteroidData[base + 25] | 0;
    const classCode = asteroidData[base + 26] | 0;
    const spkid = asteroidData[base + 27] | 0;
    const diameter = asteroidData[base + 19];
    const H = asteroidData[base + 18];
    const rotPer = asteroidData[base + 28];
    const moid = asteroidData[base + 17];
    const q = asteroidData[base + 14];
    const ad = asteroidData[base + 15];
    const per = asteroidData[base + 16];
    const albedo = asteroidData[base + 20];

    const pdes = readStr(pdesOff, pdesStart, i);
    const meta: AsteroidMeta = {
      fullName: readStr(fullOff, fullStart, i),
      pdes,
      name: readStr(nameOff, nameStart, i),
      spkid,
      flags,
      classCode,
      diameter,
      H,
      rotPer,
      moid,
      q,
      ad,
      per,
      albedo,
    };
    if (sentryMap.has(pdes)) meta.sentry = sentryMap.get(pdes);
    asteroidMeta[i] = meta;
    asteroidFlags[i] = 1; // visible by default
  }

  onProgress?.(`parsing ${cometIdx.count.toLocaleString()} comets…`);
  const cometData = new Float32Array(cometBinBuf);
  const cometStride = cometIdx.stride;
  const cN = cometIdx.count;

  const u8c = new Uint8Array(cometStringsBuf);
  const dvc = new DataView(cometStringsBuf);
  const cFullStart = dvc.getUint32(0, true);
  const cPdesStart = dvc.getUint32(4, true);
  const cFullOff = new Uint32Array(cometIdx.stringOffsets.fullName);
  const cPdesOff = new Uint32Array(cometIdx.stringOffsets.pdes);
  const cometMeta: CometMeta[] = new Array(cN);
  const cometFlags = new Uint8Array(cN);
  for (let i = 0; i < cN; i++) {
    const base = i * cometStride;
    const flags = cometData[base + 23] | 0;
    const pdes = readStr.call(null, cPdesOff, cPdesStart, i);
    const meta: CometMeta = {
      fullName: readStr.call(null, cFullOff, cFullStart, i),
      pdes,
      isHyperbolic: (flags & 1) !== 0,
      diameter: cometData[base + 18],
    };
    cometMeta[i] = meta;
    cometFlags[i] = 1;
  }

  // The readStr `this` was set to null above; make a no-this version.
  function readStr2(
    u8: Uint8Array,
    offsets: Uint32Array,
    base: number,
    idx: number,
  ): string {
    const start = offsets[idx] + base;
    const len = offsets[idx + 1] - offsets[idx];
    if (len <= 0) return "";
    return dec.decode(u8.subarray(start, start + len));
  }
  // Re-read correctly:
  for (let i = 0; i < cN; i++) {
    const base = i * cometStride;
    const flags = cometData[base + 23] | 0;
    cometMeta[i].fullName = readStr2(u8c, cFullOff, cFullStart, i);
    cometMeta[i].pdes = readStr2(u8c, cPdesOff, cPdesStart, i);
    cometMeta[i].isHyperbolic = (flags & 1) !== 0;
    cometMeta[i].diameter = cometData[base + 18];
  }

  return {
    planets: planetsRaw,
    asteroidCount: N,
    asteroidStride,
    asteroidData,
    asteroidFlags,
    asteroidMeta,
    sentry: sentryMap,
    closeApproaches: closeApproachesRaw,
    closeApproachIndex,
    cometCount: cN,
    cometStride,
    cometData,
    cometMeta,
    cometFlags,
  };
}

/** Build an index from pdes → asteroid index for fast lookup. */
export function buildAsteroidIndex(meta: AsteroidMeta[]): Map<string, number> {
  const m = new Map<string, number>();
  for (let i = 0; i < meta.length; i++) m.set(meta[i].pdes, i);
  return m;
}

/** Find close approaches by designation using the sorted index. */
export function findCloseApproaches(
  data: LoadedData,
  des: string,
  limit = 50,
): CloseApproach[] {
  const range = data.closeApproachIndex[des];
  if (!range) return [];
  const [start, end] = range;
  const out: CloseApproach[] = [];
  for (let i = start; i < end && out.length < limit; i++) {
    out.push(data.closeApproaches[i]);
  }
  // Return the closest N (closest first).
  out.sort((a, b) => a.dist - b.dist);
  return out;
}

/** Find upcoming close approaches between now+0 and now+windowDays. */
export function findUpcomingCloseApproaches(
  data: LoadedData,
  jd: number,
  windowDays = 365,
  maxResults = 200,
): CloseApproach[] {
  const end = jd + windowDays;
  const result: CloseApproach[] = [];
  for (const ca of data.closeApproaches) {
    if (ca.jd < jd) continue;
    if (ca.jd > end) continue;
    result.push(ca);
    if (result.length >= maxResults) break;
  }
  return result;
}
