// ---- Build starfield ----
function buildStarfield(): THREE.Points {
  const N = 8000;
  const positions = new Float32Array(N * 3);
  const colors = new Float32Array(N * 3);
  for (let i = 0; i < N; i++) {
    // Place stars on a large sphere far from origin.
    const r = 2500 + Math.random() * 200;
    const u = Math.random();
    const v = Math.random();
    const theta = 2 * Math.PI * u;
    const phi = Math.acos(2 * v - 1);
    positions[i * 3 + 0] = r * Math.sin(phi) * Math.cos(theta);
    positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    positions[i * 3 + 2] = r * Math.cos(phi);
    // Slight color variation.
    const t = Math.random();
    if (t < 0.7) {
      colors[i * 3 + 0] = 1.0;
      colors[i * 3 + 1] = 1.0;
      colors[i * 3 + 2] = 1.0;
    } else if (t < 0.85) {
      colors[i * 3 + 0] = 0.7;
      colors[i * 3 + 1] = 0.8;
      colors[i * 3 + 2] = 1.0;
    } else {
      colors[i * 3 + 0] = 1.0;
      colors[i * 3 + 1] = 0.85;
      colors[i * 3 + 2] = 0.7;
    }
  }
  const geom = new THREE.BufferGeometry();
  geom.setAttribute("position", new THREE.BufferAttribute(positions, 3));
  geom.setAttribute("color", new THREE.BufferAttribute(colors, 3));
  const mat = new THREE.PointsMaterial({
    size: 0.8,
    sizeAttenuation: true,
    vertexColors: true,
    transparent: true,
    opacity: 0.85,
    depthWrite: false,
  });
  return new THREE.Points(geom, mat);
}

// ---- Planet meshes + orbits ----
const PLANET_COLORS: Record<string, number> = {
  Mercury: 0xb0a090,
  Venus: 0xe6c187,
  Earth: 0x6cb4ff,
  Mars: 0xd56b4a,
  Jupiter: 0xd9b284,
  Saturn: 0xe6cf9b,
  Uranus: 0x9bd9e6,
  Neptune: 0x6c8eff,
};

const PLANET_DISPLAY_RADIUS: Record<string, number> = {
  Mercury: 0.025,
  Venus: 0.045,
  Earth: 0.05,
  Mars: 0.04,
  Jupiter: 0.16,
  Saturn: 0.14,
  Uranus: 0.1,
  Neptune: 0.1,
};

export function populatePlanets(
  refs: SceneRefs,
  planets: LoadedData["planets"],
): void {
  for (const p of planets) {
    const radius = PLANET_DISPLAY_RADIUS[p.name] ?? 0.05;
    const color = PLANET_COLORS[p.name] ?? 0xcccccc;

    const geo = new THREE.SphereGeometry(radius, 32, 24);
    const mat = new THREE.MeshStandardMaterial({
      color,
      roughness: 0.85,
      metalness: 0.0,
    });
    const mesh = new THREE.Mesh(geo, mat);
    mesh.userData = { kind: "planet", name: p.name };
    refs.planetMeshes.push(mesh);
    refs.scene.add(mesh);

    // Orbit polyline.
    const positions = sampleOrbit(
      [1, 0, 0],
      [0, 1, 0],
      p.a,
      p.e,
      128,
      false,
    );
    // Rotate from default (x-axis perihelion) to the planet's actual orientation.
    const orbitGeo = new THREE.BufferGeometry();
    const out = new Float32Array(positions.length);
    const om = (p.om ?? 0) * DEG;
    const w = (p.w ?? 0) * DEG;
    const i = (p.i ?? 0) * DEG;
    const cosO = Math.cos(om),
      sinO = Math.sin(om);
    const cosW = Math.cos(w),
      sinW = Math.sin(w);
    const cosI = Math.cos(i),
      sinI = Math.sin(i);
    // R = Rz(om) * Rx(i) * Rz(w)
    // Apply to (x, y, 0):
    // x' = cos(om)*(cos(w)*x - sin(w)*y) - sin(om)*(cos(i)*(sin(w)*x + cos(w)*y))
    // y' = sin(om)*(cos(w)*x - sin(w)*y) + cos(om)*(cos(i)*(sin(w)*x + cos(w)*y))
    // z' = sin(i)*(sin(w)*x + cos(w)*y)
    for (let k = 0; k < positions.length; k += 3) {
      const x = positions[k];
      const y = positions[k + 1];
      const u = cosW * x - sinW * y;
      const v = sinW * x + cosW * y;
      out[k] = cosO * u - sinO * cosI * v;
      out[k + 1] = sinO * u + cosO * cosI * v;
      out[k + 2] = sinI * v;
    }
    orbitGeo.setAttribute(
      "position",
      new THREE.BufferAttribute(out, 3),
    );
    const lineMat = new THREE.LineBasicMaterial({
      color,
      transparent: true,
      opacity: 0.18,
    });
    const line = new THREE.Line(orbitGeo, lineMat);
    refs.planetOrbits.push(line);
    refs.scene.add(line);
  }
}

/** Update planet positions for the current Julian date. */
export function updatePlanetPositions(
  refs: SceneRefs,
  planets: LoadedData["planets"],
  jd: number,
): void {
  for (let i = 0; i < planets.length; i++) {
    const p = planets[i];
    const mesh = refs.planetMeshes[i];
    const pos = computePosition(
      1,
      0,
      0,
      0,
      1,
      0,
      p.a,
      p.e,
      p.ma,
      p.n,
      p.epoch,
      jd,
      false,
    );
    // Rotate to planet's actual orientation.
    const om = (p.om ?? 0) * DEG;
    const w = (p.w ?? 0) * DEG;
    const i = (p.i ?? 0) * DEG;
    // r * (cos(nu), sin(nu)) in perifocal frame, rotated.
    const xPF = pos.r * pos.cosNu;
    const yPF = pos.r * pos.sinNu;
    const cosO = Math.cos(om),
      sinO = Math.sin(om);
    const cosW = Math.cos(w),
      sinW = Math.sin(w);
    const cosI = Math.cos(i),
      sinI = Math.sin(i);
    const u = cosW * xPF - sinW * yPF;
    const v = sinW * xPF + cosW * yPF;
    mesh.position.set(
      cosO * u - sinO * cosI * v,
      sinO * u + cosO * cosI * v,
      sinI * v,
    );
  }
}

// ---- Asteroid instanced mesh (GPU Kepler) ----
function createAsteroidMesh(
  count: number,
  stride: number,
): THREE.InstancedMesh {
  const geom = new THREE.SphereGeometry(1, 6, 4);

  // Custom shader with instanced attributes.
  const material = new THREE.ShaderMaterial({
    uniforms: {
      uTime: { value: 2460000.5 },
    },
    vertexShader: /* glsl */ `
      attribute vec3 aEx;
      attribute vec3 aEy;
      attribute float aA;
      attribute float aE;
      attribute float aMaDeg;
      attribute float aNDeg;
      attribute float aEpoch;
      attribute float aColorR;
      attribute float aColorG;
      attribute float aColorB;
      attribute float aVisible;
      attribute float aSize;
      uniform float uTime;

      varying vec3 vColor;
      varying float vVisible;

      const float PI = 3.14159265358979;
      const float TWO_PI = 6.28318530717959;

      float wrapPi(float a) {
        return mod(a + PI, TWO_PI) - PI;
      }

      void main() {
        vColor = vec3(aColorR, aColorG, aColorB);
        vVisible = aVisible;
        if (aVisible < 0.5) {
          // Off-screen
          gl_Position = vec4(2.0, 2.0, 2.0, 1.0);
          return;
        }

        float M = radians(aMaDeg + aNDeg * (uTime - aEpoch));
        M = wrapPi(M);

        // Solve Kepler: M = E - e*sin(E)
        float E = M + aE * sin(M);
        for (int i = 0; i < 6; i++) {
          float f = E - aE * sin(E) - M;
          float fp = 1.0 - aE * cos(E);
          E = E - f / fp;
        }

        float cosE = cos(E);
        float sinE = sin(E);
        float sqrtE2 = sqrt(max(0.0, 1.0 - aE*aE));
        float xPF = aA * (cosE - aE);
        float yPF = aA * sqrtE2 * sinE;
        vec3 helio = aEx * xPF + aEy * yPF;

        // Apply size scaling per instance.
        vec3 worldPos = helio + position * aSize;
        gl_Position = projectionMatrix * modelViewMatrix * vec4(worldPos, 1.0);
      }
    `,
    fragmentShader: /* glsl */ `
      varying vec3 vColor;
      varying float vVisible;
      void main() {
        if (vVisible < 0.5) discard;
        gl_FragColor = vec4(vColor, 1.0);
      }
    `,
  });

  const mesh = new THREE.InstancedMesh(geom, material, count);
  mesh.frustumCulled = false; // we cull manually via aVisible
  mesh.count = count;
  return mesh;
}

function createCometMesh(
  count: number,
  stride: number,
  hyperbolic: boolean,
): THREE.InstancedMesh {
  const geom = new THREE.SphereGeometry(1, 6, 4);

  const material = new THREE.ShaderMaterial({
    uniforms: {
      uTime: { value: 2460000.5 },
    },
    vertexShader: /* glsl */ `
      attribute vec3 aEx;
      attribute vec3 aEy;
      attribute float aA;
      attribute float aE;
      attribute float aMaDeg;
      attribute float aNDeg;
      attribute float aEpoch;
      attribute float aTp;
      attribute float aColorR;
      attribute float aColorG;
      attribute float aColorB;
      attribute float aVisible;
      attribute float aSize;
      uniform float uTime;

      varying vec3 vColor;
      varying float vVisible;

      const float PI = 3.14159265358979;
      const float TWO_PI = 6.28318530717959;

      void main() {
        vColor = vec3(aColorR, aColorG, aColorB);
        vVisible = aVisible;
        if (aVisible < 0.5) {
          gl_Position = vec4(2.0, 2.0, 2.0, 1.0);
          return;
        }

        // Use tp (time of perihelion passage) as epoch for comets — most
        // dataset entries don't have a reliable n/ma pair for parabolic cases.
        // The data provides tp for nearly all comets.
        // Compute mean anomaly at uTime using n (deg/day).
        float Mdeg = aMaDeg + aNDeg * (uTime - aEpoch);
        float M = radians(Mdeg);

        vec3 helio;
        if (aE >= 1.0) {
          // Hyperbolic Kepler: M = e*sinh(H) - H
          float H = M / max(1.0001, aE - 1.0);
          if (abs(H) < 1e-6) H = M;
          for (int i = 0; i < 24; i++) {
            float sinhH = sinh(H);
            float coshH = cosh(H);
            float f = aE * sinhH - H - M;
            float fp = aE * coshH - 1.0;
            if (abs(fp) < 1e-9) break;
            H = H - f / fp;
          }
          // For hyperbolic, a in dataset is positive (magnitude); actual a is negative.
          float aSigned = -abs(aA);
          float sqrtE2_1 = sqrt(max(0.0, aE*aE - 1.0));
          float coshH = cosh(H);
          float sinhH = sinh(H);
          float xPF = aSigned * (aE - coshH);
          float yPF = aSigned * sqrtE2_1 * sinhH;
          helio = aEx * xPF + aEy * yPF;
        } else {
          // Elliptic Kepler
          float Mw = M;
          Mw = mod(Mw + PI, TWO_PI) - PI;
          float E = Mw + aE * sin(Mw);
          for (int i = 0; i < 6; i++) {
            float f = E - aE * sin(E) - Mw;
            float fp = 1.0 - aE * cos(E);
            E = E - f / fp;
          }
          float cosE = cos(E);
          float sinE = sin(E);
          float sqrtE2 = sqrt(max(0.0, 1.0 - aE*aE));
          float xPF = aA * (cosE - aE);
          float yPF = aA * sqrtE2 * sinE;
          helio = aEx * xPF + aEy * yPF;
        }

        vec3 worldPos = helio + position * aSize;
        gl_Position = projectionMatrix * modelViewMatrix * vec4(worldPos, 1.0);
      }
    `,
    fragmentShader: /* glsl */ `
      varying vec3 vColor;
      varying float vVisible;
      void main() {
        if (vVisible < 0.5) discard;
        gl_FragColor = vec4(vColor, 1.0);
      }
    `,
  });

  const mesh = new THREE.InstancedMesh(geom, material, count);
  mesh.frustumCulled = false;
  mesh.count = count;
  return mesh;
}

// ---- Populate asteroid / comet instanced meshes after data load ----
export function populateAsteroids(refs: SceneRefs, data: LoadedData): void {
  const N = data.asteroidCount;
  const stride = data.asteroidStride;
  const src = data.asteroidData;
  const geom = refs.asteroidMesh.geometry;

  // Per-instance attributes.
  const ex = new Float32Array(N * 3);
  const ey = new Float32Array(N * 3);
  const a = new Float32Array(N);
  const ecc = new Float32Array(N);
  const ma = new Float32Array(N);
  const n = new Float32Array(N);
  const epoch = new Float32Array(N);
  const cR = new Float32Array(N);
  const cG = new Float32Array(N);
  const cB = new Float32Array(N);
  const visible = new Float32Array(N);
  const size = new Float32Array(N);

  // Display size by H magnitude (lower H = brighter = bigger point).
  // Most NEOs have H 18-28; a 0.5 km asteroid ~ H 17.8.
  for (let i = 0; i < N; i++) {
    const base = i * stride;
    ex[i * 3 + 0] = src[base + 0];
    ex[i * 3 + 1] = src[base + 1];
    ex[i * 3 + 2] = src[base + 2];
    ey[i * 3 + 0] = src[base + 3];
    ey[i * 3 + 1] = src[base + 4];
    ey[i * 3 + 2] = src[base + 5];
    a[i] = src[base + 9];
    ecc[i] = src[base + 10];
    ma[i] = src[base + 11];
    n[i] = src[base + 12];
    epoch[i] = src[base + 13];
    cR[i] = src[base + 22];
    cG[i] = src[base + 23];
    cB[i] = src[base + 24];
    visible[i] = 1;

    // Size based on H (absolute magnitude): H 10 = 0.04, H 28 = 0.005
    const H = src[base + 18];
    // Use exponential decay in H; very large objects get a small bonus.
    const baseSize = 0.004 + 0.025 * Math.exp(-(H - 10) * 0.18);
    // Boost for known-diameter objects.
    const hasDiam = (src[base + 25] & 8) !== 0;
    size[i] = baseSize * (hasDiam ? 1.6 : 1.0);
  }

  geom.setAttribute("aEx", new THREE.InstancedBufferAttribute(ex, 3));
  geom.setAttribute("aEy", new THREE.InstancedBufferAttribute(ey, 3));
  geom.setAttribute("aA", new THREE.InstancedBufferAttribute(a, 1));
  geom.setAttribute("aE", new THREE.InstancedBufferAttribute(ecc, 1));
  geom.setAttribute("aMaDeg", new THREE.InstancedBufferAttribute(ma, 1));
  geom.setAttribute("aNDeg", new THREE.InstancedBufferAttribute(n, 1));
  geom.setAttribute("aEpoch", new THREE.InstancedBufferAttribute(epoch, 1));
  geom.setAttribute("aColorR", new THREE.InstancedBufferAttribute(cR, 1));
  geom.setAttribute("aColorG", new THREE.InstancedBufferAttribute(cG, 1));
  geom.setAttribute("aColorB", new THREE.InstancedBufferAttribute(cB, 1));
  geom.setAttribute("aVisible", new THREE.InstancedBufferAttribute(visible, 1));
  geom.setAttribute("aSize", new THREE.InstancedBufferAttribute(size, 1));

  refs.asteroidMesh.count = N;
  refs.asteroidMesh.instanceMatrix.setUsage(THREE.DynamicDrawUsage);

  // Also store a reference to the per-instance visible array for fast updates.
  (refs.asteroidMesh.userData as any).visibleArr = visible;
  (refs.asteroidMesh.userData as any).sizeArr = size;
}

export function populateComets(refs: SceneRefs, data: LoadedData): void {
  // Split comets into elliptic vs hyperbolic, build two instanced meshes.
  const cN = data.cometCount;
  const cStride = data.cometStride;
  const src = data.cometData;
  let eCount = 0,
    hCount = 0;
  for (let i = 0; i < cN; i++) {
    if (src[i * cStride + 10] >= 1) hCount++;
    else eCount++;
  }

  function buildOne(target: THREE.InstancedMesh, indices: number[], hyperbolic: boolean) {
    const M = indices.length;
    const ex = new Float32Array(M * 3);
    const ey = new Float32Array(M * 3);
    const aA = new Float32Array(M);
    const ecc = new Float32Array(M);
    const ma = new Float32Array(M);
    const n = new Float32Array(M);
    const epoch = new Float32Array(M);
    const tp = new Float32Array(M);
    const cR = new Float32Array(M);
    const cG = new Float32Array(M);
    const cB = new Float32Array(M);
    const visible = new Float32Array(M);
    const size = new Float32Array(M);

    for (let k = 0; k < M; k++) {
      const i = indices[k];
      const base = i * cStride;
      ex[k * 3 + 0] = src[base + 0];
      ex[k * 3 + 1] = src[base + 1];
      ex[k * 3 + 2] = src[base + 2];
      ey[k * 3 + 0] = src[base + 3];
      ey[k * 3 + 1] = src[base + 4];
      ey[k * 3 + 2] = src[base + 5];
      aA[k] = src[base + 9];
      ecc[k] = src[base + 10];
      ma[k] = src[base + 11];
      n[k] = src[base + 12];
      epoch[k] = src[base + 13];
      tp[k] = src[base + 16];
      // Slightly different shade for hyperbolic
      cR[k] = 0.7;
      cG[k] = 0.85;
      cB[k] = hyperbolic ? 1.0 : 0.95;
      visible[k] = 1;
      const H = src[base + 17]; // M1 magnitude
      const baseSize = 0.005 + 0.04 * Math.exp(-(H - 4) * 0.18);
      size[k] = baseSize;
    }

    const geom = target.geometry;
    geom.setAttribute("aEx", new THREE.InstancedBufferAttribute(ex, 3));
    geom.setAttribute("aEy", new THREE.InstancedBufferAttribute(ey, 3));
    geom.setAttribute("aA", new THREE.InstancedBufferAttribute(aA, 1));
    geom.setAttribute("aE", new THREE.InstancedBufferAttribute(ecc, 1));
    geom.setAttribute("aMaDeg", new THREE.InstancedBufferAttribute(ma, 1));
    geom.setAttribute("aNDeg", new THREE.InstancedBufferAttribute(n, 1));
    geom.setAttribute("aEpoch", new THREE.InstancedBufferAttribute(epoch, 1));
    geom.setAttribute("aTp", new THREE.InstancedBufferAttribute(tp, 1));
    geom.setAttribute("aColorR", new THREE.InstancedBufferAttribute(cR, 1));
    geom.setAttribute("aColorG", new THREE.InstancedBufferAttribute(cG, 1));
    geom.setAttribute("aColorB", new THREE.InstancedBufferAttribute(cB, 1));
    geom.setAttribute("aVisible", new THREE.InstancedBufferAttribute(visible, 1));
    geom.setAttribute("aSize", new THREE.InstancedBufferAttribute(size, 1));

    target.count = M;
    target.instanceMatrix.setUsage(THREE.DynamicDrawUsage);
    (target.userData as any).visibleArr = visible;
  }

  const ellipticIdx: number[] = [];
  const hyperbolicIdx: number[] = [];
  for (let i = 0; i < cN; i++) {
    if (src[i * cStride + 10] >= 1) hyperbolicIdx.push(i);
    else ellipticIdx.push(i);
  }
  buildOne(refs.cometMeshElliptic, ellipticIdx, false);
  buildOne(refs.cometMeshHyperbolic, hyperbolicIdx, true);
}

// ---- Visibility update from filters ----
export function applyFilters(
  refs: SceneRefs,
  data: LoadedData,
  filters: FilterState,
  searchHits: Set<number> | null,
): { visibleAsteroids: number; visibleComets: number } {
  // Asteroid visibility.
  const visibleArr = (refs.asteroidMesh.userData as any).visibleArr as Float32Array;
  let visibleAsteroids = 0;
  for (let i = 0; i < data.asteroidCount; i++) {
    const base = i * data.asteroidStride;
    const flags = data.asteroidData[base + 25] | 0;
    const classCode = data.asteroidData[base + 26] | 0;
    const diameter = data.asteroidData[base + 19];
    const moid = data.asteroidData[base + 17];
    const isNeo = (flags & 1) !== 0;
    const isPha = (flags & 2) !== 0;
    const isSentry = (flags & 4) !== 0;
    const hasDiam = (flags & 8) !== 0;

    let visible = 1;
    if (!isNeo) visible = 0;
    if (filters.phaOnly && !isPha) visible = 0;
    if (filters.sentryOnly && !isSentry) visible = 0;
    if (filters.classCode && filters.classCode !== classCode) visible = 0;
    if (filters.minDiameter > 0) {
      if (!hasDiam || diameter < filters.minDiameter) visible = 0;
    }
    if (filters.maxMoid > 0 && moid > filters.maxMoid) visible = 0;
    if (searchHits && searchHits.size > 0 && !searchHits.has(i)) visible = 0;
    visibleArr[i] = visible;
    if (visible) visibleAsteroids++;
  }
  // Mark instanced attribute as needing upload.
  const attr = refs.asteroidMesh.geometry.getAttribute(
    "aVisible",
  ) as THREE.InstancedBufferAttribute;
  attr.needsUpdate = true;

  // Comet visibility — only show when comets toggle on.
  const cometEllVis = (refs.cometMeshElliptic.userData as any).visibleArr as
    | Float32Array
    | undefined;
  const cometHypVis = (refs.cometMeshHyperbolic.userData as any).visibleArr as
    | Float32Array
    | undefined;
  let visibleComets = 0;
  if (cometEllVis) {
    const v = filters.comets ? 1 : 0;
    for (let i = 0; i < cometEllVis.length; i++) {
      cometEllVis[i] = v;
      if (v) visibleComets++;
    }
    const a = refs.cometMeshElliptic.geometry.getAttribute(
      "aVisible",
    ) as THREE.InstancedBufferAttribute;
    a.needsUpdate = true;
  }
  if (cometHypVis) {
    const v = filters.comets ? 1 : 0;
    for (let i = 0; i < cometHypVis.length; i++) {
      cometHypVis[i] = v;
      if (v) visibleComets++;
    }
    const a = refs.cometMeshHyperbolic.geometry.getAttribute(
      "aVisible",
    ) as THREE.InstancedBufferAttribute;
    a.needsUpdate = true;
  }

  // Planet orbits visibility.
  for (const line of refs.planetOrbits) {
    line.visible = filters.orbits;
  }

  return { visibleAsteroids, visibleComets };
}

// ---- Update asteroid instance color (boost selected) ----
export function highlightAsteroid(
  refs: SceneRefs,
  data: LoadedData,
  pdes: string | null,
  color: [number, number, number] = [1, 0.85, 0.4],
): void {
  // Reset all colors to their stored values; then override the selected one.
  const cR = (refs.asteroidMesh.geometry.getAttribute("aColorR") as any)
    .array as Float32Array;
  const cG = (refs.asteroidMesh.geometry.getAttribute("aColorG") as any)
    .array as Float32Array;
  const cB = (refs.asteroidMesh.geometry.getAttribute("aColorB") as any)
    .array as Float32Array;
  const sizeArr = (refs.asteroidMesh.geometry.getAttribute("aSize") as any)
    .array as Float32Array;

  if (pdes === null) {
    // Restore original colors from data.
    const stride = data.asteroidStride;
    for (let i = 0; i < data.asteroidCount; i++) {
      const base = i * stride;
      cR[i] = data.asteroidData[base + 22];
      cG[i] = data.asteroidData[base + 23];
      cB[i] = data.asteroidData[base + 24];
    }
  } else {
    const idx = data.asteroidMeta.findIndex((m) => m.pdes === pdes);
    if (idx >= 0) {
      cR[idx] = color[0];
      cG[idx] = color[1];
      cB[idx] = color[2];
      sizeArr[idx] *= 1.8;
    }
  }
  (
    refs.asteroidMesh.geometry.getAttribute("aColorR") as THREE.InstancedBufferAttribute
  ).needsUpdate = true;
  (
    refs.asteroidMesh.geometry.getAttribute("aColorG") as THREE.InstancedBufferAttribute
  ).needsUpdate = true;
  (
    refs.asteroidMesh.geometry.getAttribute("aColorB") as THREE.InstancedBufferAttribute
  ).needsUpdate = true;
  (
    refs.asteroidMesh.geometry.getAttribute("aSize") as THREE.InstancedBufferAttribute
  ).needsUpdate = true;
}

// ---- Show orbit of selected body ----
export function showOrbitFor(
  refs: SceneRefs,
  data: LoadedData,
  pdes: string | null,
): void {
  if (!pdes) {
    refs.selectedOrbit.visible = false;
    refs.highlightOrbit.visible = false;
    return;
  }
  const idx = data.asteroidMeta.findIndex((m) => m.pdes === pdes);
  if (idx < 0) {
    refs.selectedOrbit.visible = false;
    refs.highlightOrbit.visible = false;
    return;
  }
  const stride = data.asteroidStride;
  const base = idx * stride;
  const ex: [number, number, number] = [
    data.asteroidData[base + 0],
    data.asteroidData[base + 1],
    data.asteroidData[base + 2],
  ];
  const ey: [number, number, number] = [
    data.asteroidData[base + 3],
    data.asteroidData[base + 4],
    data.asteroidData[base + 5],
  ];
  const a = data.asteroidData[base + 9];
  const e = data.asteroidData[base + 10];
  const isHyp = e >= 1;
  const segments = isHyp ? 200 : 256;
  const positions = sampleOrbit(ex, ey, Math.abs(a), e, segments, isHyp);
  const posAttr = refs.selectedOrbit.geometry.getAttribute(
    "position",
  ) as THREE.BufferAttribute;
  if (posAttr.array.length !== positions.length) {
    refs.selectedOrbit.geometry.setAttribute(
      "position",
      new THREE.BufferAttribute(positions, 3),
    );
  } else {
    (posAttr.array as Float32Array).set(positions);
    posAttr.needsUpdate = true;
  }
  refs.selectedOrbit.geometry.computeBoundingSphere();
  refs.selectedOrbit.visible = true;
  refs.highlightOrbit.visible = false;
}

// ---- Apply camera state from URL share ----
export function applyCameraState(
  refs: SceneRefs,
  state: CameraState | null,
): void {
  if (!state) return;
  refs.camera.position.set(state.x, state.y, state.z);
  refs.camera.lookAt(state.tx, state.ty, state.tz);
  refs.controls.target.set(state.tx, state.ty, state.tz);
  refs.controls.update();
}

export function readCameraState(refs: SceneRefs): CameraState {
  const p = refs.camera.position;
  const t = refs.controls.target;
  return { x: p.x, y: p.y, z: p.z, tx: t.x, ty: t.y, tz: t.z };
}
