    filterMoid: $("filter-moid") as HTMLInputElement,
    filterSearch: $("filter-search") as HTMLInputElement,
    filterReset: $("filter-reset") as HTMLButtonElement,
    statsSub: $("stats-sub"),
    uiDate: $("ui-date"),
    uiSpeed: $("ui-speed"),
    uiShown: $("ui-shown"),
