{"filePath":"/Users/mikevalstar/projects/nbench/2026-06-20-08-40-48-minimax-code-minimax-m3-medium/src/scene.ts","oldString":"// ---- Populate asteroid / comet instanced meshes after data load ----
export function populateAsteroids(refs: SceneRefs, data: LoadedData): void {
  const N = data.asteroidCount;
  const stride = data.asteroidStride;
  const src = data.asteroidData;
  const geom = refs.asteroidMesh.geometry;

  // Per-instance attributes.
  const ex = new Float32Array(N * 3);
  const ey = new Float32Array(N * 3);
  const a = new Float32Array(N);
  const ecc = new Float32Array(N);
  const ma = new Float32Array(N);
  const n = new Float32Array(N);
  const epoch = new Float32Array(N);
  const cR = new Float32Array(N);
  const cG = new Float32Array(N);
  const cB = new Float32Array(N);
  const visible = new Float32Array(N);
  const size = new Float32Array(N);

  // Display size by H magnitude (lower H = brighter = bigger point).
  // Most NEOs have H 18-28; a 0.5 km asteroid ~ H 17.8.
  for (let i = 0; i < N; i++) {
    const base = i * stride;
    ex[i * 3 + 0] = src[base + 0];
    ex[i * 3 + 1] = src[base + 1];
    ex[i * 3 + 2] = src[base + 2];
    ey[i * 3 + 0] = src[base + 3];
    ey[i * 3 + 1] = src[base + 4];
    ey[i * 3 + 2] = src[base + 5];
    a[i] = src[base + 9];
    ecc[i] = src[base + 10];
    ma[i] = src[base + 11];
    n[i] = src[base + 12];
    epoch[i] = src[base + 13];
    cR[i] = src[base + 22];
    cG[i] = src[base + 23];
    cB[i] = src[base + 24];
    visible[i] = 1;

    // Size based on H (absolute magnitude): H 10 = 0.04, H 28 = 0.005
    const H = src[base + 18];
    // Use exponential decay in H; very large objects get a small bonus.
    const baseSize = 0.004 + 0.025 * Math.exp(-(H - 10) * 0.18);
    // Boost for known-diameter objects.
    const hasDiam = (src[base + 25] & 8) !== 0;
    size[i] = baseSize * (hasDiam ? 1.6 : 1.0);
  }

  geom.setAttribute("aEx", new THREE.InstancedBufferAttribute(ex, 3));
  geom.setAttribute("aEy", new THREE.InstancedBufferAttribute(ey, 3));
  geom.setAttribute("aA", new THREE.InstancedBufferAttribute(a, 1));
  geom.setAttribute("aE", new THREE.InstancedBufferAttribute(ecc, 1));
  geom.setAttribute("aMaDeg", new THREE.InstancedBufferAttribute(ma, 1));
  geom.setAttribute("aNDeg", new THREE.InstancedBufferAttribute(n, 1));
  geom.setAttribute("aEpoch", new THREE.InstancedBufferAttribute(epoch, 1));
  geom.setAttribute("aColorR", new THREE.InstancedBufferAttribute(cR, 1));
  geom.setAttribute("aColorG", new THREE.InstancedBufferAttribute(cG, 1));
  geom.setAttribute("aColorB", new THREE.InstancedBufferAttribute(cB, 1));
  geom.setAttribute("aVisible", new THREE.InstancedBufferAttribute(visible, 1));
  geom.setAttribute("aSize", new THREE.InstancedBufferAttribute(size, 1));

  refs.asteroidMesh.count = N;
  refs.asteroidMesh.instanceMatrix.setUsage(THREE.DynamicDrawUsage);

  // Also store a reference to the per-instance visible array for fast updates.
  (refs.asteroidMesh.userData as any).visibleArr = visible;
  (refs.asteroidMesh.userData as any).sizeArr = size;
}

export function populateComets(refs: SceneRefs, data: LoadedData): void {
  // Split comets into elliptic vs hyperbolic, build two instanced meshes.
  const cN = data.cometCount;
  const cStride = data.cometStride;
  const src = data.cometData;
  let eCount = 0,
    hCount = 0;
  for (let i = 0; i < cN; i++) {
    if (src[i * cStride + 10] >= 1) hCount++;
    else eCount++;
  }

  function buildOne(target: THREE.InstancedMesh, indices: number[], hyperbolic: boolean) {
    const M = indices.length;
    const ex = new Float32Array(M * 3);
    const ey = new Float32Array(M * 3);
    const aA = new Float32Array(M);
    const ecc = new Float32Array(M);
    const ma = new Float32Array(M);
    const n = new Float32Array(M);
    const epoch = new Float32Array(M);
    const tp = new Float32Array(M);
    const cR = new Float32Array(M);
    const cG = new Float32Array(M);
    const cB = new Float32Array(M);
    const visible = new Float32Array(M);
    const size = new Float32Array(M);

    for (let k = 0; k < M; k++) {
      const i = indices[k];
      const base = i * cStride;
      ex[k * 3 + 0] = src[base + 0];
      ex[k * 3 + 1] = src[base + 1];
      ex[k * 3 + 2] = src[base + 2];
      ey[k * 3 + 0] = src[base + 3];
      ey[k * 3 + 1] = src[base + 4];
      ey[k * 3 + 2] = src[base + 5];
      aA[k] = src[base + 9];
      ecc[k] = src[base + 10];
      ma[k] = src[base + 11];
      n[k] = src[base + 12];
      epoch[k] = src[base + 13];
      tp[k] = src[base + 16];
      // Slightly different shade for hyperbolic
      cR[k] = 0.7;
      cG[k] = 0.85;
      cB[k] = hyperbolic ? 1.0 : 0.95;
      visible[k] = 1;
      const H = src[base + 17]; // M1 magnitude
      const baseSize = 0.005 + 0.04 * Math.exp(-(H - 4) * 0.18);
      size[k] = baseSize;
    }

    const geom = target.geometry;
    geom.setAttribute("aEx", new THREE.InstancedBufferAttribute(ex, 3));
    geom.setAttribute("aEy", new THREE.InstancedBufferAttribute(ey, 3));
    geom.setAttribute("aA", new THREE.InstancedBufferAttribute(aA, 1));
    geom.setAttribute("aE", new THREE.InstancedBufferAttribute(ecc, 1));
    geom.setAttribute("aMaDeg", new THREE.InstancedBufferAttribute(ma, 1));
    geom.setAttribute("aNDeg", new THREE.InstancedBufferAttribute(n, 1));
    geom.setAttribute("aEpoch", new THREE.InstancedBufferAttribute(epoch, 1));
    geom.setAttribute("aTp", new THREE.InstancedBufferAttribute(tp, 1));
    geom.setAttribute("aColorR", new THREE.InstancedBufferAttribute(cR, 1));
    geom.setAttribute("aColorG", new THREE.InstancedBufferAttribute(cG, 1));
    geom.setAttribute("aColorB", new THREE.InstancedBufferAttribute(cB, 1));
    geom.setAttribute("aVisible", new THREE.InstancedBufferAttribute(visible, 1));
    geom.setAttribute("aSize", new THREE.InstancedBufferAttribute(size, 1));

    target.count = M;
    target.instanceMatrix.setUsage(THREE.DynamicDrawUsage);
    (target.userData as any).visibleArr = visible;
