{"content":"#!/usr/bin/env python3
import asyncio, sys
from playwright.async_api import async_playwright

async def main():
    console = []
    async with async_playwright() as p:
        browser = await p.chromium.launch(headless=True, args=["--use-gl=swiftshader", "--enable-webgl"])
        page = await (await browser.new_context(viewport={"width": 1280, "height": 800})).new_page()
        page.on("console", lambda msg: console.append(f"{msg.type}: {msg.text}"))
        page.on("pageerror", lambda err: console.append(f"PAGEERR: {err.message}"))
        await page.goto("http://127.0.0.1:5004/", wait_until="load", timeout=30000)
        await page.wait_for_function(
            "() => !document.getElementById('loading') || document.getElementById('loading').style.display === 'none'",
            timeout=20000,
        )
        await page.wait_for_timeout(1000)

        # Default scene
        await page.screenshot(path="/tmp/scene-default.png")

        # Apply PHAs only filter
        await page.click("#filter-pha")
        await page.wait_for_timeout(500)
        info = await page.evaluate("""() => ({
            shown: document.getElementById('ui-shown').textContent,
        })""")
        print("After PHA filter:", info)
        await page.screenshot(path="/tmp/scene-pha.png")

        # Reset and zoom out via wheel
        await page.click("#filter-reset")
        await page.wait_for_timeout(500)
        # Zoom out by simulating wheel events
        for _ in range(20):
            await page.mouse.wheel(0, 200)
            await page.wait_for_timeout(20)
        await page.wait_for_timeout(500)
        info2 = await page.evaluate("""() => ({
            shown: document.getElementById('ui-shown').textContent,
        })""")
        print("After zoom out:", info2)
        await page.screenshot(path="/tmp/scene-zoomed.png")

        # Sample pixels in the center
        pix = await page.evaluate("""() => {
            const c = document.getElementById('scene');
            const ctx = c.getContext('webgl2') || c.getContext('webgl');
            const px = new Uint8Array(4 * 100);
            ctx.readPixels(c.width/2 - 5, c.height/2 - 5, 10, 10, ctx.RGBA, ctx.UNSIGNED_BYTE, px);
            // Sum of non-black pixels
            let lit = 0;
            for (let i = 0; i < px.length; i += 4) {
                if (px[i] > 5 || px[i+1] > 5 || px[i+2] > 5) lit++;
            }
            return { lit, total: px.length / 4 };
        }""")
        print("Center pixels lit:", pix)

        await browser.close()
    print("=== CONSOLE (last 5) ===")
    for c in console[-5:]:
        print(c)

asyncio.run(main())
