function packStringTable(strings) {
  // Build a single Uint8Array of UTF-8 bytes prefixed with 4-byte little-endian length.
  let total = 0;
  const enc = strings.map((s) => {
    const buf = new TextEncoder().encode(s ?? "");
    total += buf.length + 4;
    return buf;
  });
  const out = new Uint8Array(total);
  const offsets = new Uint32Array(strings.length + 1);
  let off = 0;
  for (let i = 0; i < enc.length; i++) {
    offsets[i] = off;
    out[off] = enc[i].length & 0xff;
    out[off + 1] = (enc[i].length >>> 8) & 0xff;
    out[off + 2] = (enc[i].length >>> 16) & 0xff;
    out[off + 3] = (enc[i].length >>> 24) & 0xff;
    off += 4;
    out.set(enc[i], off);
    off += enc[i].length;
  }
  offsets[enc.length] = off;
  return { bytes: out, offsets };
}
